import os

BASE = '/Users/vbalaraman/OpenSpider/workspace/pitwall-ai/frontend'

def w(path, content):
    full = os.path.join(BASE, path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, 'w') as f:
        f.write(content)
    print(f'Wrote {full}')

