w('src/components/Navbar.tsx', """import { Link } from 'react-router-dom'\n\nexport default function Navbar() {\n  return (\n    <nav className=\"border-b border-pitwall-border bg-pitwall-card/80 backdrop-blur-sm sticky top-0 z-50\">\n      <div className=\"container mx-auto px-4 h-16 flex items-center justify-between\">\n        <Link to=\"/\" className=\"flex items-center gap-2\">\n          <span className=\"text-pitwall-accent font-bold text-2xl font-mono\">PITWALL</span>\n          <span className=\"text-pitwall-text-muted text-sm\">.ai</span>\n        </Link>\n        <div className=\"flex items-center gap-6\">\n          <Link to=\"/\" className=\"text-pitwall-text-muted hover:text-pitwall-text transition-colors text-sm font-medium\">\n            Dashboard\n          </Link>\n          <Link to=\"/drivers/2025\" className=\"text-pitwall-text-muted hover:text-pitwall-text transition-colors text-sm font-medium\">\n            Drivers\n          </Link>\n          <div className=\"h-4 w-px bg-pitwall-border\"></div>\n          <span className=\"text-xs text-pitwall-text-muted font-mono\">2025</span>\n        </div>\n      </div>\n    </nav>\n  )\n}\n""")

# src/pages/Dashboard.tsx
w('src/pages/Dashboard.tsx', """import { useEffect, useState } from 'react'\nimport { Link } from 'react-router-dom'\nimport { getRaces } from '../api'\n\ninterface RaceEvent {\n  round_number: number\n  country: string\n  location: string\n  event_name: string\n  event_date: string | null\n  event_format: string\n}\n\nexport default function Dashboard() {\n  const [races, setRaces] = useState<RaceEvent[]>([])\n  const [loading, setLoading] = useState(true)\n  const [year] = useState(2025)\n\n  useEffect(() => {\n    getRaces(year)\n      .then((res) => setRaces(res.data.events || []))\n      .catch((err) => console.error('Failed to load races:', err))\n      .finally(() => setLoading(false))\n  }, [year])\n\n  return (\n    <div>\n      <div className=\"mb-8\">\n        <h1 className=\"text-3xl font-bold font-mono\">\n          <span className=\"text-pitwall-accent\">F1</span> {year} Season\n        </h1>\n        <p className=\"text-pitwall-text-muted mt-1\">Race calendar and analytics dashboard</p>\n      </div>\n\n      {loading ? (\n        <div className=\"flex items-center justify-center h-64\">\n          <div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-pitwall-accent\"></div>\n        </div>\n      ) : (\n        <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4\">\n          {races.map((race) => (\n            <Link\n              key={race.round_number}\n              to={`/race/${year}/${race.round_number}`}\n              className=\"group border border-pitwall-border bg-pitwall-card rounded-lg p-5 hover:border-pitwall-accent/50 transition-all duration-200\"\n            >\n              <div className=\"flex items-start justify-between\">\n                <div>\n                  <span className=\"text-pitwall-accent font-mono text-sm font-bold\">\n                    R{String(race.round_number).padStart(2, '0')}\n                  </span>\n                  <h3 className=\"text-lg font-semibold mt-1 group-hover:text-pitwall-accent transition-colors\">\n                    {race.country}\n                  </h3>\n                  <p className=\"text-pitwall-text-muted text-sm\">{race.location}</p>\n                </div>\n                <span className=\"text-xs text-pitwall-text-muted font-mono bg-pitwall-bg px-2 py-1 rounded\">\n                  {race.event_format}\n                </span>\n              </div>\n              {race.event_date && (\n                <p className=\"text-xs text-pitwall-text-muted mt-3 font-mono\">\n                  {new Date(race.event_date).toLocaleDateString('en-US', {\n                    month: 'short',\n                    day: 'numeric',\n                  })}\n                </p>\n              )}\n            </Link>\n          ))}\n        </div>\n      )}\n    </div>\n  )\n}\n""")

# src/pages/RaceDetail.tsx
w('src/pages/RaceDetail.tsx', """import { useEffect, useState } from 'react'\nimport { useParams } from 'react-router-dom'\nimport { getRaceResults, getStrategy } from '../api'\n\ninterface Result {\n  Position: number\n  Abbreviation: string\n  BroadcastName: string\n  TeamName: string\n  GridPosition: number\n  Status: string\n  Points: number\n}\n\ninterface Stint {\n  Driver: string\n  Stint: number\n  Compound: string\n  StintStartLap: number\n  StintEndLap: number\n  TotalLaps: number\n}\n\nconst compoundColors: Record<string, string> = {\n  SOFT: 'bg-red-500',\n  MEDIUM: 'bg-yellow-400',\n  HARD: 'bg-gray-200',\n  INTERMEDIATE: 'bg-green-500',\n  WET: 'bg-blue-500',\n}\n\nexport default function RaceDetail() {\n  const { year, round } = useParams()\n  const [results, setResults] = useState<Result[]>([])\n  const [strategy, setStrategy] = useState<Stint[]>([])\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    if (!year || !round) return\n    const y = parseInt(year)\n    const r = parseInt(round)\n    Promise.all([\n      getRaceResults(y, r).then((res) => setResults(res.data.results || [])),\n      getStrategy(y, r).then((res) => setStrategy(res.data.strategy || [])),\n    ])\n      .catch((err) => console.error('Failed to load race data:', err))\n      .finally(() => setLoading(false))\n  }, [year, round])\n\n  if (loading) {\n    return (\n      <div className=\"flex items-center justify-center h-64\">\n        <div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-pitwall-accent\"></div>\n      </div>\n    )\n  }\n\n  return (\n    <div>\n      <h1 className=\"text-2xl font-bold font-mono mb-6\">\n        <span className=\"text-pitwall-accent\">Round {round}</span> - {year} Season\n      </h1>\n\n      {/* Results Table */}\n      <div className=\"border border-pitwall-border bg-pitwall-card rounded-lg overflow-hidden mb-8\">\n        <div className=\"px-5 py-3 border-b border-pitwall-border\">\n          <h2 className=\"font-semibold font-mono text-sm text-pitwall-accent\">RACE CLASSIFICATION</h2>\n        </div>\n        <table className=\"w-full text-sm\">\n          <thead>\n            <tr className=\"border-b border-pitwall-border text-pitwall-text-muted text-xs font-mono\">\n              <th className=\"px-4 py-2 text-left\">POS</th>\n              <th className=\"px-4 py-2 text-left\">DRIVER</th>\n              <th className=\"px-4 py-2 text-left\">TEAM</th>\n              <th className=\"px-4 py-2 text-center\">GRID</th>\n              <th className=\"px-4 py-2 text-left\">STATUS</th>\n              <th className=\"px-4 py-2 text-right\">PTS</th>\n            </tr>\n          </thead>\n          <tbody>\n            {results.map((r, i) => (\n              <tr key={i} className=\"border-b border-pitwall-border/50 hover:bg-pitwall-bg/50 transition-colors\">\n                <td className=\"px-4 py-2 font-mono font-bold\">\n                  {r.Position <= 3 ? (\n                    <span className={r.Position === 1 ? 'text-yellow-400' : r.Position === 2 ? 'text-gray-300' : 'text-amber-600'}>\n                      P{r.Position}\n                    </span>\n                  ) : (\n                    <span>P{r.Position}</span>\n                  )}\n                </td>\n                <td className=\"px-4 py-2 font-semibold\">{r.Abbreviation}</td>\n                <td className=\"px-4 py-2 text-pitwall-text-muted\">{r.TeamName}</td>\n                <td className=\"px-4 py-2 text-center font-mono\">{r.GridPosition}</td>\n                <td className=\"px-4 py-2 text-pitwall-text-muted text-xs\">{r.Status}</td>\n                <td className=\"px-4 py-2 text-right font-mono font-bold\">{r.Points}</td>\n              </tr>\n            ))}\n          </tbody>\n        </table>\n      </div>\n\n      {/* Tire Strategy */}\n      <div className=\"border border-pitwall-border bg-pitwall-card rounded-lg overflow-hidden\">\n        <div className=\"px-5 py-3 border-b border-pitwall-border\">\n          <h2 className=\"font-semibold font-mono text-sm text-pitwall-accent\">TIRE STRATEGY</h2>\n        </div>\n        <div className=\"p-5 space-y-2\">\n          {Array.from(new Set(strategy.map((s) => s.Driver))).map((driver) => {\n            const driverStints = strategy.filter((s) => s.Driver === driver)\n            const maxLap = Math.max(...strategy.map((s) => s.StintEndLap))\n            return (\n              <div key={driver} className=\"flex items-center gap-3\">\n                <span className=\"w-10 font-mono text-xs font-bold text-pitwall-text-muted\">{driver}</span>\n                <div className=\"flex-1 flex h-6 gap-px\">\n                  {driverStints.map((stint, i) => {\n                    const width = ((stint.TotalLaps / maxLap) * 100).toFixed(1)\n                    return (\n                      <div\n                        key={i}\n                        className={`${compoundColors[stint.Compound] || 'bg-gray-500'} rounded-sm flex items-center justify-center text-[10px] font-mono font-bold text-black`}\n                        style={{ width: `${width}%` }}\n                        title={`${stint.Compound} - Laps ${stint.StintStartLap}-${stint.StintEndLap} (${stint.TotalLaps} laps)`}\n                      >\n                        {stint.TotalLaps > 5 ? stint.Compound[0] : ''}\n                      </div>\n                    )\n                  })}\n                </div>\n              </div>\n            )\n          })}\n        </div>\n      </div>\n    </div>\n  )\n}\n""")

# src/pages/Drivers.tsx
w('src/pages/Drivers.tsx', """import { useEffect, useState } from 'react'\nimport { useParams } from 'react-router-dom'\nimport { getDrivers } from '../api'\n\ninterface Driver {\n  driver_number: string\n  broadcast_name: string\n  abbreviation: string\n  team_name: string\n}\n\nexport default function Drivers() {\n  const { year } = useParams()\n  const [drivers, setDrivers] = useState<Driver[]>([])\n  const [loading, setLoading] = useState(true)\n\n  useEffect(() => {\n    if (!year) return\n    getDrivers(parseInt(year))\n      .then((res) => setDrivers(res.data.drivers || []))\n      .catch((err) => console.error('Failed to load drivers:', err))\n      .finally(() => setLoading(false))\n  }, [year])\n\n  if (loading) {\n    return (\n      <div className=\"flex items-center justify-center h-64\">\n        <div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-pitwall-accent\"></div>\n      </div>\n    )\n  }\n\n  return (\n    <div>\n      <h1 className=\"text-2xl font-bold font-mono mb-6\">\n        <span className=\"text-pitwall-accent\">Drivers</span> - {year} Season\n      </h1>\n      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4\">\n        {drivers.map((d) => (\n          <div\n            key={d.driver_number}\n            className=\"border border-pitwall-border bg-pitwall-card rounded-lg p-5 hover:border-pitwall-accent/50 transition-all\"\n          >\n            <div className=\"flex items-center justify-between mb-2\">\n              <span className=\"text-2xl font-bold font-mono text-pitwall-accent\">\n                {d.abbreviation}\n              </span>\n              <span className=\"text-pitwall-text-muted font-mono text-sm\">#{d.driver_number}</span>\n            </div>\n            <p className=\"font-semibold\">{d.broadcast_name}</p>\n            <p className=\"text-pitwall-text-muted text-sm mt-1\">{d.team_name}</p>\n          </div>\n        ))}\n      </div>\n    </div>\n  )\n}\n""")

